// src/components/FormPanel.jsx

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {

  // Esta função precisa atualizar o estado corretamente
  const handleChange = (field) => (e) => {
    const newValue = e.target.value;
    setForm((prev) => ({ 
      ...prev, 
      [field]: newValue 
    }));
  };

  return (
    <aside className="pb-sidebar">
      {/* CAMPO NOME */}
      <input
        className="pb-input"
        value={form.name || ""} // O value deve vir do estado
        onChange={handleChange("name")} // O onChange deve atualizar o estado
      />

      {/* CAMPO SERVIÇO */}
      <select
        className="pb-select"
        value={form.service || ""}
        onChange={handleChange("service")}
      >
        <option value="">Selecione...</option>
        {/* ... seus serviços aqui ... */}
      </select>

      {/* BOTÃO */}
      <button onClick={onSubmit}>Confirmar</button>
    </aside>
  );
}
